import{_ as a,c as e,o as m,b as t}from"./app.aaa68922.js";const y='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 5","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 5","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 1.","toc":true,"tags":"vim-1","sans":"\u0909\u0926\u094D\u092F\u092E\u094B \u092D\u0948\u0930\u0935\u0903","trans":"Udyamo bhairava\u1E25","date":"2021-02-20T00:00:00.000Z"},"headers":[{"level":3,"title":"Udyamo bhairava\u1E25||5||","slug":"udyamo-bhairavah-5"},{"level":3,"title":"Bhairava --\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E-- (bhairava\u1E25) - (\u044D\u0442\u043E) \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u0430\u044F \u0432\u0441\u043F\u044B\u0448\u043A\u0430, \u0438\u043B\u0438 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F (udyama\u1E25)||5||","slug":"bhairava-\u0432\u044B\u0441\u0448\u0435\u0435-\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E-bhairavah-\u044D\u0442\u043E-\u0432\u043D\u0435\u0437\u0430\u043F\u043D\u0430\u044F-\u0432\u0441\u043F\u044B\u0448\u043A\u0430-\u0438n\u0438-\u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435-\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E-\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-udyamah-5"}],"relativePath":"texts/shiva-sutra-vimarshini/1/5.md"}',i={},r=t('<div class="stanza"><a href="#s1.5" id="s1.5" class="num">1.5</a><div class="sans"><p>\u0905\u0925\u0948\u0924\u0926\u094D\u092C\u0928\u094D\u0927\u092A\u094D\u0930\u0936\u092E\u094B\u092A\u093E\u092F\u092E\u0941\u092A\u0947\u092F\u0935\u093F\u0936\u094D\u0930\u093E\u0928\u094D\u0924\u093F\u0938\u0924\u0924\u094D\u0924\u094D\u0935\u092E\u093E\u0926\u093F\u0936\u0924\u093F\u2014</p><blockquote><p><strong>\u0909\u0926\u094D\u092F\u092E\u094B \u092D\u0948\u0930\u0935\u0903\u0965\u096B\u0965</strong></p></blockquote><p>\u092F\u094B\u093D\u092F\u0902 \u092A\u094D\u0930\u0938\u0930\u0926\u094D\u0930\u0942\u092A\u093E\u092F\u093E \u0935\u093F\u092E\u0930\u094D\u0936\u092E\u092F\u094D\u092F\u093E\u0903 \u0938\u0902\u0935\u093F\u0926\u094B \u091D\u0917\u093F\u0924\u094D\u092F\u0941\u091A\u094D\u091B\u0932\u0928\u093E\u0924\u094D\u092E\u0915\u092A\u0930\u092A\u094D\u0930\u0924\u093F\u092D\u094B\u0928\u094D\u092E\u091C\u094D\u091C\u0928\u0930\u0942\u092A \u0909\u0926\u094D\u092F\u092E\u0903 \u0938 \u090F\u0935 \u0938\u0930\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u0938\u093E\u092E\u0930\u0938\u094D\u092F\u0947\u0928\u093E\u0936\u0947\u0937\u0935\u093F\u0936\u094D\u0935\u092D\u0930\u093F\u0924\u0924\u094D\u0935\u093E\u0924\u094D\u0938\u0915\u0932\u0915\u0932\u094D\u092A\u0928\u093E\u0915\u0941\u0932\u093E\u0932\u0919\u094D\u0915\u0935\u0932\u0928\u092E\u092F\u0924\u094D\u0935\u093E\u091A\u094D\u091A \u092D\u0948\u0930\u0935\u094B \u092D\u0948\u0930\u0935\u093E\u0924\u094D\u092E\u0915\u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u093E\u092D\u093F\u0935\u094D\u092F\u0915\u094D\u0924\u093F\u0939\u0947\u0924\u0941\u0924\u094D\u0935\u093E\u0926\u094D\u092D\u0915\u094D\u0924\u093F\u092D\u093E\u091C\u093E\u092E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0948\u0924\u0924\u094D\u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0935\u0927\u093E\u0928\u0927\u0928\u093E\u0928\u093E\u0902 \u091C\u093E\u092F\u0924 \u0907\u0924\u094D\u092F\u0941\u092A\u0926\u093F\u0937\u094D\u091F\u0902 \u092D\u0935\u0924\u093F\u0964 \u0909\u0915\u094D\u0924\u0902 \u091A \u0936\u094D\u0930\u0940\u092E\u093E\u0932\u093F\u0928\u0940\u0935\u093F\u091C\u092F\u0947</p><blockquote><p>\u0905\u0915\u093F\u091E\u094D\u091A\u093F\u091A\u094D\u091A\u093F\u0928\u094D\u0924\u0915\u0938\u094D\u092F\u0948\u0935 \u0917\u0941\u0930\u0941\u0923\u093E \u092A\u094D\u0930\u0924\u093F\u092C\u094B\u0927\u0924\u0903|<br> \u091C\u093E\u092F\u0924\u0947 \u092F\u0903 \u0938\u092E\u093E\u0935\u0947\u0936\u0903 \u0936\u093E\u092E\u094D\u092D\u0935\u094B\u093D\u0938\u093E\u0935\u0941\u0926\u0940\u0930\u093F\u0924\u0903\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0905\u0924\u094D\u0930 \u0939\u093F \u0917\u0941\u0930\u0941\u0923\u093E \u092A\u094D\u0930\u0924\u093F\u092C\u094B\u0927\u0924 \u0907\u0924\u094D\u092F\u0924\u094D\u0930 \u0917\u0941\u0930\u0941\u0924\u0903 \u0938\u094D\u0935\u0938\u094D\u092E\u093E\u0924\u094D\u092A\u094D\u0930\u0924\u093F\u092C\u094B\u0927\u0924 \u0907\u0924\u094D\u092F\u0938\u094D\u092F\u093E\u0930\u094D\u0925\u094B \u0917\u0941\u0930\u0941\u092D\u093F\u0930\u093E\u0926\u093F\u0937\u094D\u091F\u0903\u0964 \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947\u093D\u092A\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u094D</p><blockquote><p>\u0906\u0924\u094D\u092E\u0928\u094B \u092D\u0948\u0930\u0935\u0902 \u0930\u0942\u092A\u0902 \u092D\u093E\u0935\u092F\u0947\u0926\u094D\u092F\u0938\u094D\u0924\u0941 \u092A\u0941\u0930\u0941\u0937\u0903|<br> \u0924\u0938\u094D\u092F \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0903 \u092A\u094D\u0930\u0938\u093F\u0926\u094D\u0927\u094D\u092F\u0928\u094D\u0924\u093F \u0928\u093F\u0924\u094D\u092F\u092F\u0941\u0915\u094D\u0924\u0938\u094D\u092F \u0938\u0941\u0928\u094D\u0926\u0930\u093F\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u092D\u093E\u0935\u0928\u0902 \u0939\u094D\u092F\u0924\u094D\u0930\u093E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u094B\u0926\u094D\u092F\u0928\u094D\u0924\u0943\u0924\u093E\u092A\u0926\u0935\u093F\u092E\u0930\u094D\u0936\u0928\u092E\u0947\u0935\u0964 \u090F\u0924\u091A\u094D\u091A</p><blockquote><p>\u090F\u0915\u091A\u093F\u0928\u094D\u0924\u093E\u092A\u094D\u0930\u0938\u0915\u094D\u0924\u0938\u094D\u092F \u092F\u0924\u0903 \u0938\u094D\u092F\u093E\u0926\u092A\u0930\u094B\u0926\u092F\u0903|<br> \u0909\u0928\u094D\u092E\u0947\u0937\u0903 \u0938 \u0924\u0941 \u0935\u093F\u091C\u094D\u091E\u0947\u092F\u0903 \u0938\u094D\u0935\u092F\u0902 \u0924\u092E\u0941\u092A\u0932\u0915\u094D\u0937\u092F\u0947\u0924\u094D\u0965</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0965\u096B\u0965</p></div><div class="trans"><p>Athaitadbandhapra\u015Bamop\u0101yamupeyavi\u015Br\u0101ntisatattvam\u0101di\u015Bati\u2014</p><blockquote><h3 id="udyamo-bhairavah-5" tabindex="-1">Udyamo bhairava\u1E25||5|| <a class="header-anchor" href="#udyamo-bhairavah-5" aria-hidden="true">#</a></h3></blockquote><p>Yo&#39;ya\u1E41 prasaradr\u016Bp\u0101y\u0101 vimar\u015Bamayy\u0101\u1E25 sa\u1E41vido jhagityucchalan\u0101tmakaparapratibhonmajjanar\u016Bpa udyama\u1E25 sa eva sarva\u015Baktis\u0101marasyen\u0101\u015Be\u1E63avi\u015Bvabharitatv\u0101tsakalakalpan\u0101kul\u0101la\u1E45kavalanamayatv\u0101cca bhairavo bhairav\u0101tmakasvasvar\u016Bp\u0101bhivyaktihetutv\u0101dbhaktibh\u0101j\u0101mantarmukhaitattattv\u0101vadh\u0101nadhan\u0101n\u0101\u1E41 j\u0101yata ityupadi\u1E63\u1E6Da\u1E41 bhavati| Ukta\u1E41 ca \u015Br\u012Bm\u0101lin\u012Bvijaye</p><blockquote><p>Aki\xF1ciccintakasyaiva guru\u1E47\u0101 pratibodhata\u1E25|<br> J\u0101yate ya\u1E25 sam\u0101ve\u015Ba\u1E25 \u015B\u0101mbhavo&#39;s\u0101vud\u012Brita\u1E25||</p></blockquote><p>iti| Atra hi guru\u1E47\u0101 pratibodhata ityatra guruta\u1E25 svasm\u0101tpratibodhata ityasy\u0101rtho gurubhir\u0101di\u1E63\u1E6Da\u1E25| \u015Ar\u012Bsvacchande&#39;pyuktam</p><blockquote><p>\u0100tmano bhairava\u1E41 r\u016Bpa\u1E41 bh\u0101vayedyastu puru\u1E63a\u1E25|<br> Tasya mantr\u0101\u1E25 prasiddhyanti nityayuktasya sundari||</p></blockquote><p>iti| Bh\u0101vana\u1E41 hyatr\u0101ntarmukhodyant\u1E5Bt\u0101padavimar\u015Banameva| Etacca</p><blockquote><p>Ekacint\u0101prasaktasya yata\u1E25 sy\u0101daparodaya\u1E25|<br> Unme\u1E63a\u1E25 sa tu vij\xF1eya\u1E25 svaya\u1E41 tamupalak\u1E63ayet||</p></blockquote><p>ityanena sa\u1E45g\u1E5Bh\u012Btam||5||</p></div><p>\u0422\u0435\u043F\u0435\u0440\u044C <em>(atha)</em>, [\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0438\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C] \u0443\u0447\u0438\u0442 <em>(\u0101di\u015Bati)</em> \u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C <em>(up\u0101yam)</em> \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(pra\u015Bama)</em> \u044D\u0442\u043E\u0433\u043E <em>(etad)</em> \u0440\u0430\u0431\u0441\u0442\u0432\u0430 <em>(bandha)</em>, [\u0442\u043E \u0435\u0441\u0442\u044C,] \u0438\u0441\u0442\u0438\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u0435 <em>(satattvam)</em> \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u043D\u0438\u044F <em>(vi\u015Br\u0101nti)</em> \u0432 \u0422\u043E\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F --\u0426\u0435\u043B\u044C\u044E, \u0442.\u0435. \u0412\u044B\u0441\u0448\u0438\u043C \u042F, \u0442\u0430\u043A\u0436\u0435 \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u044B\u043C \u043A\u0430\u043A Bhairava, \u0438\u043B\u0438 \u015Aiva-- <em>(upeya)</em>\u2014</p><blockquote><h3 id="bhairava-\u0432\u044B\u0441\u0448\u0435\u0435-\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E-bhairavah-\u044D\u0442\u043E-\u0432\u043D\u0435\u0437\u0430\u043F\u043D\u0430\u044F-\u0432\u0441\u043F\u044B\u0448\u043A\u0430-\u0438n\u0438-\u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435-\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E-\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-udyamah-5" tabindex="-1">Bhairava --\u0412\u044B\u0441\u0448\u0435\u0435 \u0421\u0443\u0449\u0435\u0441\u0442\u0432\u043E-- <em>(bhairava\u1E25)</em> - (\u044D\u0442\u043E) \u0432\u043D\u0435\u0437\u0430\u043F\u043D\u0430\u044F \u0432\u0441\u043F\u044B\u0448\u043A\u0430, \u0438\u043B\u0438 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(udyama\u1E25)</em>||5|| <a class="header-anchor" href="#bhairava-\u0432\u044B\u0441\u0448\u0435\u0435-\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E-bhairavah-\u044D\u0442\u043E-\u0432\u043D\u0435\u0437\u0430\u043F\u043D\u0430\u044F-\u0432\u0441\u043F\u044B\u0448\u043A\u0430-\u0438n\u0438-\u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u0435-\u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E-\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-udyamah-5" aria-hidden="true">#</a></h3></blockquote><p>\u042D\u0442\u043E <em>(ayam)</em> \u0435\u0441\u0442\u044C udyama <em>(udyama\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 <em>(ya\u1E25)</em> (\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F) \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C <em>(unmajjana-r\u016Bpa\u1E25)</em> \u043D\u0430\u0438\u0432\u044B\u0441\u0448\u0435\u0439 <em>(para)</em> Pratibh\u0101 --\u0442.\u0435. Par\u0101v\u0101k, \u0438\u043B\u0438 \u0412\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0447\u0438-- <em>(pratibh\u0101)</em>^. [\u0422\u0430\u043A\u0430\u044F Pratibh\u0101] \u0441\u043E\u0441\u0442\u043E\u0438\u0442 <em>(\u0101tmaka)</em> \u0438\u0437 \u043C\u0433\u043D\u043E\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(jhagiti)</em> \u043F\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(ucchalana)</em> Sa\u1E41vid --\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(sa\u1E41vida\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F --\u0442.\u0435. Sa\u1E41vid-- \u0441\u043E\u0442\u0432\u043E\u0440\u0435\u043D\u0430 <em>(mayy\u0101\u1E25)</em> \u0438\u0437 Vimar\u015Ba --\u015Aakti, \u0438\u043B\u0438 \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(vimar\u015Ba)</em> [\u0438] \u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u0443\u0435\u0442\u0441\u044F <em>(r\u016Bp\u0101y\u0101\u1E25)</em> \u0440\u0430\u0441\u0448\u0438\u0440\u0435\u043D\u0438\u0435\u043C [\u0432 \u0444\u043E\u0440\u043C\u0435 \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439] <em>(prasarat)</em>. \u042D\u0442\u043E\u0442 <em>(sa\u1E25)</em> \u0441\u0430\u043C\u044B\u0439 <em>(eva)</em> [udyama \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] Bhairava --\u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0439 \u015Aiva-- <em>(bhairava\u1E25)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 [Bhairava] \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D <em>(bharitatv\u0101t)</em> \u0432\u0441\u0435\u0439 <em>(a\u015Be\u1E63a)</em> \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439 <em>(vi\u015Bva)</em>, \u043E\u0441\u0442\u0430\u0432\u0430\u044F\u0441\u044C \u0432 \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435 <em>(s\u0101marasyena)</em> \u0441\u043E \u0432\u0441\u0435\u043C\u0438 <em>(sarva)</em> \u015Bakti-s, \u0438\u043B\u0438 \u0441\u0438\u043B\u0430\u043C\u0438 <em>(\u015Bakti)</em>, [\u0438] \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u041E\u043D \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 <em>(mayatv\u0101t)</em> \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C\u044E <em>(alam)</em> \u043F\u043E\u0433\u043B\u043E\u0449\u0430\u0442\u044C <em>(kavalana)</em> \u0446\u0435\u043B\u0443\u044E <em>(sakala)</em> \u0433\u0440\u0443\u043F\u043F\u0443 <em>(kula)</em> \u0438\u0434\u0435\u0439, [\u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u044F\u0449\u0438\u0445 \u0434\u0443\u0430\u043B\u0438\u0437\u043C] <em>(kalpan\u0101)</em>. [\u0422\u0430\u043A\u043E\u0439 udyama - \u044D\u0442\u043E \u0442\u0430\u043A\u0436\u0435 Bhairava], \u0442.\u043A. \u043E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u043E\u0439 <em>(hetutv\u0101t)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F <em>(abhivyakti)</em> \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B <em>(sva-r\u016Bpa)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0435\u0441\u0442\u044C <em>(\u0101tmaka)</em>, [\u0432 \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u043C \u0441\u0447\u0435\u0442\u0435,] Bhairava <em>(bhairava)</em> [\u0442\u0430\u043A\u0436\u0435. \u0418 udyama] \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(j\u0101yate)</em> \u0432 \u0442\u0435\u0445, \u043A\u0442\u043E \u043E\u0431\u043B\u0430\u0434\u0430\u0435\u0442 <em>(bh\u0101j\u0101m)</em> \u043F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435\u043C <em>(bhakti)</em> [\u0438] \u0441\u043E\u043A\u0440\u043E\u0432\u0438\u0449\u0435\u043C <em>(dhan\u0101n\u0101m)</em> \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F <em>(avadh\u0101na)</em> \u043A \u044D\u0442\u043E\u043C\u0443 <em>(etad)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u043C\u0443 <em>(antas-mukha)</em> \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0443 --\u0442.\u0435. Bhairava, \u0411\u043E\u0433\u0443-- <em>(tattva)</em>. \u042D\u0442\u043E \u0442\u043E <em>(iti... bhavati)</em>, \u0447\u0435\u043C\u0443 \u0443\u0447\u0438\u0442 <em>(upadi\u1E63\u1E6Dam)</em> [\u0434\u0430\u043D\u043D\u044B\u0439 \u0430\u0444\u043E\u0440\u0438\u0437\u043C]|</p><p>\u0411\u044B\u043B\u043E \u0438\u0437\u043B\u043E\u0436\u0435\u043D\u043E <em>(uktam ca)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u043C <em>(\u015Br\u012B)</em> M\u0101lin\u012Bvijayatantra <em>(m\u0101lin\u012Bvijaye)</em>:</p><blockquote><p>&quot;\u0413\u043E\u0432\u043E\u0440\u044F\u0442 <em>(ud\uFFFD\uFFFDrita\u1E25)</em>, \u0447\u0442\u043E \u015B\u0101mbhava-sam\u0101ve\u015Ba, \u0438\u043B\u0438 \u043F\u043E\u0433\u043B\u043E\u0449\u0435\u043D\u0438\u0435 \u0432 \u015Aiva <em>(sam\u0101ve\u015Ba\u1E25 \u015B\u0101mbhava\u1E25)</em> - [\u044D\u0442\u043E] \u0442\u043E <em>(asau)</em>, \u0447\u0442\u043E <em>(ya\u1E25)</em> \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u0435\u0442 <em>(j\u0101yate)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(eva)</em> \u0432 \u0442\u043E\u043C, \u043A\u0442\u043E \u043D\u0435 \u0434\u0443\u043C\u0430\u0435\u0442 <em>(cintakasya)</em> \u043D\u0438 \u043E \u0447\u0435\u043C <em>(aki\xF1cid)</em>, \u0431\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u044E <em>(pratibodhata\u1E25)</em>, [\u043F\u043E\u043B\u0443\u0447\u0435\u043D\u043D\u043E\u043C\u0443] \u043E\u0442 \u0413\u0443\u0440\u0443 <em>(guru\u1E47\u0101... iti)</em>&quot;||<br> [\u0421\u043C. M\u0101lin\u012Bvijayatantra II, 23]</p></blockquote><p>\u0412 \u044D\u0442\u043E\u043C \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u0438 <em>(atra hi)</em>, (\u0444\u0440\u0430\u0437\u0430) &quot;guru\u1E47\u0101 pratibodhata\u1E25&quot; <em>(guru\u1E47\u0101 pratibodhata\u1E25 iti)</em> [\u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0442\u0430\u043A\u0436\u0435 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u043D\u0430] \u0437\u0434\u0435\u0441\u044C <em>(atra)</em> \u043A\u0430\u043A &quot;\u0447\u0435\u0440\u0435\u0437 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 <em>(svasm\u0101t)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0435 <em>(guruta\u1E25)</em> \u043F\u0440\u043E\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(pratibodhata\u1E25 iti)</em>&quot;^. [\u0410\u043B\u044C\u0442\u0435\u0440\u043D\u0430\u0442\u0438\u0432\u043D\u043E\u0435] \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(artha\u1E25)</em> \u044D\u0442\u043E\u0439 [\u0444\u0440\u0430\u0437\u044B] <em>(asya)</em> \u0431\u044B\u043B\u043E \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u043D\u043E <em>(\u0101di\u1E63\u1E6Da\u1E25)</em> \u0413\u0443\u0440\u0443 <em>(gurubhi\u1E25)</em>|</p><p>[\u042D\u0442\u043E] \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0430\u0435\u0442\u0441\u044F <em>(uktam)</em> \u0432 \u043E\u0441\u0432\u044F\u0449\u0435\u043D\u043D\u043E\u043C \u0432\u0435\u043A\u0430\u043C\u0438 <em>(\u015Br\u012B)</em> Svacchandatantra <em>(svacchande)</em> \u0442\u0430\u043A\u0436\u0435 <em>(api)</em>:</p><blockquote><p>&quot;\u041E \u043F\u0440\u0435\u043A\u0440\u0430\u0441\u043D\u0430\u044F <em>(sundari)</em>^, \u043E\u043F\u0440\u0435\u0434\u0435\u043B\u0435\u043D\u043D\u043E <em>(tu)</em>, \u0434\u043B\u044F \u0442\u043E\u0433\u043E <em>(tasya)</em> \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 <em>(puru\u1E63a\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 <em>(ya\u1E25)</em> \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442, \u0438\u043B\u0438 \u043F\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(bh\u0101vayet)</em>, \u0447\u0442\u043E \u0435\u0433\u043E <em>(\u0101tmana\u1E25)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(r\u016Bpam)</em> [\u0435\u0441\u0442\u044C] Bhairava <em>(bhairavam)</em>, \u043A\u043E\u0433\u0434\u0430 \u043E\u043D \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442\u0441\u044F <em>(yuktasya)</em> \u0441 \u0412\u0435\u0447\u043D\u043E\u0441\u0442\u044C\u044E <em>(nitya)</em>, Mantra-s <em>(mantr\u0101\u1E25)</em> \u043F\u0440\u0438\u043D\u043E\u0441\u044F\u0442 [\u0435\u043C\u0443] \u043F\u043B\u043E\u0434\u044B <em>(prasiddhyanti... iti)</em>&quot;||</p></blockquote><p>\u041D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, [\u0441\u043B\u043E\u0432\u043E] bh\u0101vana --\u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0432 \u0441\u043F\u0440\u044F\u0436\u0435\u043D\u0438\u0438 &quot;bh\u0101vayet&quot;, \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u044E\u0449\u0435\u0435\u0441\u044F \u0432 \u0441\u0442\u0440\u043E\u0444\u0435 Svacchandatantra-- <em>(bh\u0101vanam)</em>, [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0437\u0434\u0435\u0441\u044C <em>(atra)</em> \u043F\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 <em>(vimar\u015Banam eva)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pada)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(antas-mukha)</em> \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u0438\u044F <em>(udyant\u1E5Bt\u0101)</em>|</p><p>\u042D\u0442\u0430 [\u0438\u0434\u0435\u044F] <em>(etad ca)</em> \u0431\u044B\u043B\u0430 [\u0442\u0430\u043A\u0436\u0435] \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u0430 <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u0432 \u044D\u0442\u043E\u0439 [\u0441\u0442\u0440\u043E\u0444\u0435 Spandak\u0101rik\u0101-s] <em>(anena)</em>:</p><blockquote><p>&quot;\u042D\u0442\u043E <em>(sa\u1E25)</em> \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E <em>(tu vij\xF1eya\u1E25)</em>, \u043A\u0430\u043A Unme\u1E63a <em>(unme\u1E63a\u1E25)</em>, \u043E\u0442\u043A\u0443\u0434\u0430 _(yatas) \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 _(sy\u0101t) \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u0435 _(udaya\u1E25) \u0434\u0440\u0443\u0433\u043E\u0433\u043E [\u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F --\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E K\u1E63emar\u0101ja-- \u0438\u043B\u0438 (\u0434\u0440\u0443\u0433\u043E\u0439) \u043C\u044B\u0441\u043B\u0438 --\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0438\u043D\u044B\u043C \u043C\u043D\u0435\u043D\u0438\u044F\u043C--] <em>(apara)</em>^ \u0432 [\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435], \u043A\u043E\u0442\u043E\u0440\u044B\u0439 [\u0443\u0436\u0435] \u0437\u0430\u043D\u044F\u0442 <em>(prasaktasya)</em> \u043E\u0434\u043D\u043E\u0439 <em>(eka)</em> \u043C\u044B\u0441\u043B\u044C\u044E <em>(cint\u0101)</em>. \u0415\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0449\u0443\u0442\u0438\u0442\u044C _(upalak\u1E63ayet) \u044D\u0442\u043E [Unme\u1E63a] <em>(tam)</em> \u0441\u0430\u043C\u043E\u043C\u0443 <em>(svayam... iti)</em>&quot;||<br> [\u0421\u043C. Spandak\u0101rik\u0101-s III, 9]</p></blockquote><p>||5||</p><hr><ol><li><p>\u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0447\u044C - \u044D\u0442\u043E \u0443\u0440\u043E\u0432\u0435\u043D\u044C, \u043D\u0430 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u0441\u043B\u043E\u0432\u0430 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u044B, \u043E\u0431\u043E\u0437\u043D\u0430\u0447\u0435\u043D\u043D\u044B\u0435 \u0438\u043C\u0438, \u043D\u0430\u0445\u043E\u0434\u044F\u0442\u0441\u044F \u0432 \u043F\u043E\u043B\u043D\u043E\u043C \u0435\u0434\u0438\u043D\u0441\u0442\u0432\u0435. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u043D\u0430 \u044D\u0442\u043E\u043C \u044D\u0442\u0430\u043F\u0435 \u043E\u043D\u0438 \u0434\u0430\u0436\u0435 \u0435\u0449\u0435 \u043D\u0435 \u043F\u043E\u044F\u0432\u0438\u043B\u0438\u0441\u044C \u043A\u0430\u043A \u0441\u043B\u043E\u0432\u0430 \u0438 \u043E\u0431\u044A\u0435\u043A\u0442\u044B. \u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C, \u0412\u044B\u0441\u0448\u0430\u044F \u0420\u0435\u0447\u044C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0441\u0438\u043D\u043E\u043D\u0438\u043C\u043E\u043C \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F, \u0438\u0437 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u0441\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F.</p></li><li><p>\u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0442\u0435\u0440\u043C\u0438\u043D &quot;\u0433\u0443\u0440\u0443&quot;, \u043F\u043E\u043C\u0438\u043C\u043E &quot;\u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0433\u043E \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A\u0430&quot;, \u0442\u0430\u043A\u0436\u0435 \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0432\u0435\u043B\u0438\u043A\u0438\u0439&quot;. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043E\u0442\u043C\u0435\u0442\u0438\u0442\u044C, \u0447\u0442\u043E \u0445\u043E\u0442\u044F &quot;\u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0439 \u043D\u0430\u0441\u0442\u0430\u0432\u043D\u0438\u043A&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0445\u043E\u0440\u043E\u0448\u0438\u043C \u043A\u043E\u0440\u043E\u0442\u043A\u0438\u043C \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u043E\u043C \u0441\u043B\u043E\u0432\u0430 &quot;\u0433\u0443\u0440\u0443&quot;, \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u044D\u0442\u043E \u043D\u0435 \u0441\u043E\u0432\u0441\u0435\u043C \u0442\u043E\u0447\u043D\u043E, \u043F\u043E \u043C\u043E\u0435\u043C\u0443 \u0441\u043A\u0440\u043E\u043C\u043D\u043E\u043C\u0443 \u043C\u043D\u0435\u043D\u0438\u044E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u0435\u043A\u0441\u0442 \u0433\u043E\u0432\u043E\u0440\u0438\u0442 \u043E \u0413\u0443\u0440\u0443, \u0442.\u0435. \u043E \u0432\u044B\u0441\u043E\u043A\u043E-\u0434\u0443\u0445\u043E\u0432\u043D\u043E\u043C \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0435, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043F\u043E\u0441\u043E\u0431\u0435\u043D \u043F\u0440\u0438\u0432\u0435\u0441\u0442\u0438 \u043E\u0431\u044B\u0447\u043D\u043E\u0433\u043E \u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430 \u0438\u0437 \u0440\u0430\u0431\u0441\u0442\u0432\u0430 \u043A \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u043C\u0443 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044E. \u0412\u043E\u0442\u043E \u043F\u043E\u0447\u0435\u043C\u0443 \u044F &quot;\u0432 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u043C&quot; \u043F\u0440\u0435\u0434\u043F\u043E\u0447\u0438\u0442\u0430\u044E \u043E\u0441\u0442\u0430\u0432\u043B\u044F\u0442\u044C \u0441\u043B\u043E\u0432\u043E &quot;\u0433\u0443\u0440\u0443&quot; \u043D\u0435\u043F\u0435\u0440\u0435\u0432\u0435\u0434\u0435\u043D\u043D\u044B\u043C.</p></li><li><p>\u0422\u0430\u043D\u0442\u0440\u044B \u043E\u0431\u044B\u0447\u043D\u043E \u0441\u043E\u0437\u0434\u0430\u044E\u0442\u0441\u044F \u0432 \u0444\u043E\u0440\u043C\u0435 \u0434\u0438\u0430\u043B\u043E\u0433\u0430 \u043C\u0435\u0436\u0434\u0443 \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C \u015Aiva \u0438 P\u0101rvat\u012B (\u015Aakti), \u0415\u0433\u043E \u0436\u0435\u043D\u043E\u0439.</p></li><li><p>K\u1E63emar\u0101ja \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043C\u0443\u0434\u0440\u0435\u0446\u043E\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u043F\u0440\u044F\u043C\u043E \u0441\u0435\u0439\u0447\u0430\u0441, \u043A\u043E\u043D\u0435\u0447\u043D\u043E. \u041E\u043D \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 Spandak\u0101rik\u0101-s \u0442\u0430\u043A\u0436\u0435.</p></li></ol></div>',1),u=[r];function o(h,p,v,s,n,d){return m(),e("div",null,u)}var c=a(i,[["render",o]]);export{y as __pageData,c as default};
